// Import the tools we need from React
import { createContext, useState, useContext, useEffect } from 'react';

// Create an empty "container" that will hold and share the cart data
const CartContext = createContext();

// CartProvider is a wrapper component — it wraps the whole app
// "children" means whatever is inside it (all your other components)
export function CartProvider({ children }) {

   // The actual cart items (array of products)
  const [cart, setCart] = useState([]);

  // How many items are in the cart (for the header icon)
  const [cartCount, setCartCount] = useState(0);

  // Function that calls the backend to get the current cart data, and updates the state
  const fetchCart = async () => {
    const res = await fetch('http://localhost:5001/api/cart', {
      credentials: 'include' // Send session cookie so backend knows who we are
    });
    const data = await res.json(); // Get the JSON data from the response
    setCart(data.cart); // Update the cart items in state
    setCartCount(data.total_items); // Update the cart count in state
  };

  // When the CartProvider component is first loaded, fetch the cart data from the backend
  useEffect(() => {
      fetchCart();
    }, []);

  return (

    // Make cart and cartCount available to all components inside
    <CartContext.Provider value={{ cart, cartCount }}>
      {children}
    </CartContext.Provider>
    );
}

// A shortcut hook — instead of useContext(CartContext) every time,
// any component can just write useCart() to access the cart data and count
export function useCart() {
  return useContext(CartContext);
}
